def split_words(txt):
    if ' ' in txt:
        return txt.split()
    elif ',' in txt:
        return txt.split(',')
    else:
        count = 0
        for char in txt:
            if 'a' <= char <= 'z':
                order = ord(char) - ord('a')
                if order % 2 != 0:
                    count += 1
        return count
```

